"""Pure end-of-turn checks for editorial turns."""

from __future__ import annotations

from dataclasses import dataclass, field
from typing import Any


DEFAULT_END_OF_TURN_ACKNOWLEDGMENT = "Done."


@dataclass(frozen=True)
class EndOfTurnToolCall:
    name: str
    operation_kind: str
    result: dict[str, Any] = field(default_factory=dict)


@dataclass(frozen=True)
class EndOfTurnFinding:
    category: str
    message: str
    details: dict[str, Any] = field(default_factory=dict)


@dataclass(frozen=True)
class EndOfTurnDecision:
    findings: tuple[EndOfTurnFinding, ...]
    should_send_default_acknowledgment: bool
    should_error_empty_response: bool


def evaluate_end_of_turn(
    *,
    user_message: str,
    response_text: str | None,
    reply_sent: bool,
    tool_calls: list[EndOfTurnToolCall],
    body_before: str | None,
    body_after: str | None,
    checklist_before: list[dict[str, Any]],
    checklist_after: list[dict[str, Any]],
) -> EndOfTurnDecision:
    """Return deterministic end-of-turn findings without side effects."""

    normalized_response = (response_text or "").strip()
    body_changed = (body_before or "") != (body_after or "")
    checklist_changed = _checklist_signature(checklist_before) != _checklist_signature(
        checklist_after
    )
    progress_made = body_changed or checklist_changed or _has_substantive_tool_work(tool_calls)
    message_will_be_sent = reply_sent or bool(normalized_response)

    findings: list[EndOfTurnFinding] = []
    if not message_will_be_sent:
        findings.append(
            EndOfTurnFinding(
                category="no_message_sent",
                message="Turn reached completion without an outbound message.",
            )
        )
    if not tool_calls and not body_changed and not checklist_changed:
        findings.append(
            EndOfTurnFinding(
                category="no_tool_calls_or_progress",
                message="Turn produced no tool calls or persisted progress.",
            )
        )
    if not normalized_response:
        findings.append(
            EndOfTurnFinding(
                category="empty_response",
                message="Model response text was empty.",
                details={"response_was_none": response_text is None},
            )
        )
    if _expects_body_change(user_message, tool_calls) and not body_changed:
        findings.append(
            EndOfTurnFinding(
                category="body_unchanged_when_expected",
                message="User intent or tool plan implied a body edit, but the body did not change.",
            )
        )
    if _expects_checklist_progress(user_message, checklist_before) and not checklist_changed:
        findings.append(
            EndOfTurnFinding(
                category="checklist_stall",
                message="Checklist progress was expected, but checklist state did not change.",
                details={"open_items": _open_checklist_count(checklist_before)},
            )
        )

    return EndOfTurnDecision(
        findings=tuple(findings),
        should_send_default_acknowledgment=not message_will_be_sent and progress_made,
        should_error_empty_response=not normalized_response and not progress_made,
    )


def _has_substantive_tool_work(tool_calls: list[EndOfTurnToolCall]) -> bool:
    for call in tool_calls:
        if call.operation_kind != "write":
            continue
        if call.name in {
            "send_message",
            "set_activity",
            "defer_to_caller",
            "list_feedback",
            "list_observations",
        }:
            continue
        if isinstance(call.result, dict) and call.result.get("error"):
            continue
        return True
    return False


def _expects_body_change(
    user_message: str,
    tool_calls: list[EndOfTurnToolCall],
) -> bool:
    if any(call.name in {"create_epic", "edit_epic"} for call in tool_calls):
        return True
    lowered = user_message.lower()
    edit_verbs = (
        "add ",
        "change ",
        "delete ",
        "edit ",
        "expand ",
        "remove ",
        "rewrite ",
        "tighten ",
        "update ",
    )
    body_targets = (
        "body",
        "copy",
        "description",
        "draft",
        "epic",
        "goal",
        "section",
        "part about",
    )
    return any(verb in lowered for verb in edit_verbs) and any(
        target in lowered for target in body_targets
    )


def _expects_checklist_progress(
    user_message: str,
    checklist_before: list[dict[str, Any]],
) -> bool:
    if not _open_checklist_count(checklist_before):
        return False
    lowered = user_message.lower()
    checklist_terms = ("checklist", "mark", "complete", "finish", "done")
    item_terms = ("item", "task", "todo", "next")
    return any(term in lowered for term in checklist_terms) and any(
        term in lowered for term in item_terms
    )


def _open_checklist_count(items: list[dict[str, Any]]) -> int:
    return sum(1 for item in items if str(item.get("status") or "open") != "done")


def _checklist_signature(items: list[dict[str, Any]]) -> tuple[tuple[str, str, str], ...]:
    return tuple(
        sorted(
            (
                str(item.get("id") or ""),
                str(item.get("label") or item.get("title") or ""),
                str(item.get("status") or ""),
            )
            for item in items
        )
    )


__all__ = [
    "DEFAULT_END_OF_TURN_ACKNOWLEDGMENT",
    "EndOfTurnDecision",
    "EndOfTurnFinding",
    "EndOfTurnToolCall",
    "evaluate_end_of_turn",
]

"""System prompt loading and versioning."""

from __future__ import annotations

from hashlib import sha256
from pathlib import Path
from typing import Any


JSONDict = dict[str, Any]
SYSTEM_PROMPT_PATH = Path(__file__).resolve().parents[1] / "prompts" / "system.md"


def load_system_prompt() -> str:
    return SYSTEM_PROMPT_PATH.read_text(encoding="utf-8")


def system_prompt_version(content: str | None = None) -> str:
    prompt = load_system_prompt() if content is None else content
    return sha256(prompt.encode("utf-8")).hexdigest()[:8]


def build_system_prompt(hot_context: JSONDict | None = None) -> str:
    prompt = load_system_prompt()
    if not hot_context:
        return prompt

    active_feedback = hot_context.get("active_feedback") or []
    unresolved_observations = hot_context.get("unresolved_observations") or []
    sprints = hot_context.get("sprints") or []
    response_policy = hot_context.get("response_policy") or {}
    resolved_reference = hot_context.get("resolved_reference") or {}
    dynamic_sections: list[str] = []
    if sprints:
        dynamic_sections.append(
            "\n".join(
                ["# Sprint Snapshot"]
                + [
                    f"- Sprint {row.get('sprint_number')}: {row.get('name')} "
                    f"[{row.get('status')}], queue_position={row.get('queue_position')}, "
                    f"pending_reason={row.get('pending_reason')}"
                    for row in sprints
                ]
            )
        )
    if hot_context.get("all_sprints_pending_no_queued"):
        dynamic_sections.append(
            "# Sprint Warning\nAll sprints are pending and no sprint is queued."
        )
    if active_feedback:
        dynamic_sections.append(
            "\n".join(
                ["# Active Feedback"]
                + [
                    f"- {row.get('kind')}: {row.get('content')} "
                    f"(id: {row.get('id')}, last_applied_at: {row.get('last_applied_at')})"
                    for row in active_feedback
                ]
            )
        )
    if unresolved_observations:
        dynamic_sections.append(
            "\n".join(
                ["# Recent Unresolved Observations"]
                + [
                    f"- {row.get('kind')}: {row.get('content')} (id: {row.get('id')})"
                    for row in unresolved_observations
                ]
            )
        )
    if response_policy:
        lines = ["# Response Policy"]
        mode = response_policy.get("mode")
        if mode:
            lines.append(f"- User mode: {mode}")
        if response_policy.get("conversation_gap_acknowledgment", {}).get("should_acknowledge"):
            hours = response_policy["conversation_gap_acknowledgment"].get("hours")
            lines.append(f"- Briefly acknowledge the conversation gap ({hours} hours) before continuing.")
        if mode == "deep-thinking":
            lines.append("- Be measured and substantive; include reasoning where it changes the decision.")
        elif mode == "brainstorming":
            lines.append("- Be exploratory; offer alternatives without over-settling too early.")
        elif mode == "executing":
            lines.append("- Be direct; take a position and keep elaboration minimal.")
        dynamic_sections.append("\n".join(lines))
    if resolved_reference:
        if resolved_reference.get("resolved"):
            dynamic_sections.append(
                "# Resolved User Reference\n"
                f"- Target: {resolved_reference.get('target')}"
            )
        elif resolved_reference.get("reason") == "ambiguous_deictic":
            dynamic_sections.append(
                "# Reference Ambiguity\n"
                "- The user's reference to the previous bot output is ambiguous; ask a focused clarification."
            )
    if not dynamic_sections:
        return prompt
    return prompt.rstrip() + "\n\n" + "\n\n".join(dynamic_sections) + "\n"


DEFAULT_PROMPT_VERSION = system_prompt_version()


__all__ = [
    "DEFAULT_PROMPT_VERSION",
    "SYSTEM_PROMPT_PATH",
    "build_system_prompt",
    "load_system_prompt",
    "system_prompt_version",
]

