"""Minimal invocation-mode communication tools."""

from __future__ import annotations

from typing import Any

from agent_kit.logging import log
from agent_kit.tool_kit import ExternalSpec, ToolContext, register_tool


SEND_MESSAGE_SCHEMA = {
    "type": "object",
    "additionalProperties": False,
    "required": ["content"],
    "properties": {
        "content": {"type": "string"},
        "attach_files": {
            "type": ["array", "null"],
            "items": {"type": "string"},
        },
    },
}

SET_ACTIVITY_SCHEMA = {
    "type": "object",
    "additionalProperties": False,
    "required": ["description"],
    "properties": {
        "description": {"type": "string"},
    },
}

DEFER_TO_CALLER_SCHEMA = {
    "type": "object",
    "additionalProperties": False,
    "required": ["questions"],
    "properties": {
        "questions": {
            "type": "array",
            "items": {"type": "string"},
        },
        "reason": {"type": ["string", "null"]},
    },
}


@register_tool(
    "send_message",
    schema=SEND_MESSAGE_SCHEMA,
    event_kind="tool_call",
    operation_kind="write",
)
def send_message(
    context: ToolContext,
    content: str,
    attach_files: list[str] | None = None,
) -> str:
    del attach_files
    context.reply_buffer.append(content)
    is_resident = context.transport is not None
    # Resident sends must wait for Discord confirmation before filling the external id.
    message = context.store.create_message(
        epic_id=context.metadata.get("epic_id"),
        direction="outbound",
        content=content,
        bot_turn_id=context.turn_id,
        synthesize_outbound_id=not is_resident,
    )
    if not is_resident:
        return message["discord_message_id"]

    channel_id = str(context.metadata.get("channel_id") or "")
    endpoint = f"POST /channels/{channel_id}/messages"

    def _post_and_update():
        response = context.transport.post_message(channel_id, content)  # type: ignore[union-attr]
        discord_message_id = (
            response.get("discord_message_id")
            or response.get("id")
            or response.get("message_id")
        )
        if discord_message_id is not None:
            context.store.update_message(
                message["id"],
                discord_message_id=str(discord_message_id),
            )
        return (
            str(discord_message_id) if discord_message_id is not None else None,
            response,
        )

    if context.external_queue is None:
        context.external_queue = []
    context.external_queue.append(
        (
            ExternalSpec(
                provider="discord",
                endpoint=endpoint,
                request_summary={
                    "content_preview": content[:100],
                    "channel_id": channel_id,
                    "message_row_id": message["id"],
                },
            ),
            _post_and_update,
        )
    )
    return message["id"]


@register_tool(
    "set_activity",
    schema=SET_ACTIVITY_SCHEMA,
    event_kind="activity",
    operation_kind="write",
)
def set_activity(context: ToolContext, description: str) -> dict[str, str]:
    if len(description) > 80:
        original_length = len(description)
        description = description[:80]
        log(
            context.store,
            "warn",
            "tool",
            "activity_truncated",
            "Activity description exceeded 80 characters and was truncated.",
            turn_id=context.turn_id,
            epic_id=context.metadata.get("epic_id"),
            original_length=original_length,
            truncated_length=len(description),
        )
    context.store.update_turn(context.turn_id, current_activity=description)
    return {"description": description}


@register_tool(
    "defer_to_caller",
    schema=DEFER_TO_CALLER_SCHEMA,
    event_kind="tool_call",
    operation_kind="write",
)
def defer_to_caller(
    context: ToolContext,
    questions: list[str],
    reason: str | None = None,
) -> dict[str, Any]:
    context.metadata["outcome"] = "blocked_on_caller"
    context.metadata["questions"] = list(questions)
    context.metadata["defer_reason"] = reason
    context.metadata["stop_requested"] = True
    return {"questions": list(questions), "reason": reason}


__all__ = [
    "DEFER_TO_CALLER_SCHEMA",
    "SEND_MESSAGE_SCHEMA",
    "SET_ACTIVITY_SCHEMA",
    "defer_to_caller",
    "send_message",
    "set_activity",
]

"""Server-side epic state gates for Sprint 4."""

from __future__ import annotations

from dataclasses import dataclass
import re
from typing import Any

from agent_kit import body


JSONDict = dict[str, Any]
LOCKDOWN_RE = re.compile(
    r"\b(TBD|to be decided|to be determined|we'll see|figure out later|tunable|depends on what surfaces|can adjust later|decide later)\b",
    re.IGNORECASE,
)
DONE_CHECKLIST_STATUSES = {"done", "skipped", "superseded"}


@dataclass(frozen=True)
class GateResult:
    allowed: bool
    blockers: tuple[JSONDict, ...]

    def to_dict(self) -> JSONDict:
        return {"allowed": self.allowed, "blockers": list(self.blockers)}


def evaluate_state_transition(
    *,
    from_state: str,
    target_state: str,
    epic: JSONDict,
    checklist: list[JSONDict],
    sprints: list[JSONDict],
) -> GateResult:
    if from_state == target_state:
        return GateResult(True, ())
    if from_state == "shaping" and target_state == "sprinting":
        return _shaping_to_sprinting(epic, checklist)
    if from_state == "sprinting" and target_state == "planned":
        return _sprinting_to_planned(epic, checklist, sprints)
    return GateResult(
        False,
        ({"code": "unsupported_transition", "message": f"Cannot advance {from_state} -> {target_state}."},),
    )


def scan_lockdown_phrases(markdown: str) -> list[JSONDict]:
    parsed = body.parse(markdown)
    spans = _section_line_spans(markdown)
    blocked: list[JSONDict] = []
    fence: str | None = None
    for line_number, line in enumerate(markdown.splitlines(), start=1):
        stripped = line.strip()
        if fence:
            if stripped.startswith(fence):
                fence = None
            continue
        if stripped.startswith("```") or stripped.startswith("~~~"):
            fence = stripped[:3]
            continue
        section = _section_for_line(spans, line_number)
        if section == "Open Questions":
            continue
        for match in LOCKDOWN_RE.finditer(line):
            blocked.append(
                {
                    "code": "unresolved_decision_phrase",
                    "phrase": match.group(0),
                    "section": section,
                    "line_number": line_number,
                    "message": f"Unresolved decision phrase outside Open Questions: {match.group(0)}",
                }
            )
    if not parsed.sections and blocked:
        for item in blocked:
            item["section"] = None
    return blocked


def _shaping_to_sprinting(epic: JSONDict, checklist: list[JSONDict]) -> GateResult:
    markdown = str(epic.get("body") or "")
    parsed = body.parse(markdown)
    blockers: list[JSONDict] = []
    if len(markdown) <= 500:
        blockers.append({"code": "body_too_short", "message": "Body must be more than 500 characters."})
    names = {section.name for section in parsed.sections}
    for required in ("Goal", "Deliverable"):
        if required not in names:
            blockers.append({"code": "missing_section", "section": required, "message": f"Missing required section: {required}"})
    unresolved = [
        item for item in checklist
        if str(item.get("status") or "open") not in DONE_CHECKLIST_STATUSES
    ]
    if checklist and len(unresolved) > max(1, len(checklist) // 3):
        blockers.append(
            {
                "code": "checklist_not_mostly_resolved",
                "open_count": len(unresolved),
                "total_count": len(checklist),
                "message": "Checklist must be mostly resolved before sprinting.",
            }
        )
    return GateResult(not blockers, tuple(blockers))


def _sprinting_to_planned(
    epic: JSONDict,
    checklist: list[JSONDict],
    sprints: list[JSONDict],
) -> GateResult:
    blockers: list[JSONDict] = []
    markdown = str(epic.get("body") or "")
    parsed = body.parse(markdown)
    if len(markdown) <= 500:
        blockers.append({"code": "body_too_short", "message": "Body must be more than 500 characters."})
    names = {section.name for section in parsed.sections}
    for required in ("Goal", "Deliverable"):
        if required not in names:
            blockers.append({"code": "missing_section", "section": required, "message": f"Missing required section: {required}"})
    unfinished = [
        item for item in checklist
        if str(item.get("status") or "open") not in DONE_CHECKLIST_STATUSES
    ]
    if unfinished:
        blockers.append(
            {
                "code": "checklist_unfinished",
                "open_count": len(unfinished),
                "message": "Checklist items must be done, skipped, or superseded.",
            }
        )
    if not sprints:
        blockers.append({"code": "missing_sprints", "message": "At least one sprint is required."})
    for sprint in sprints:
        status = str(sprint.get("status") or "")
        if status not in {"queued", "pending"}:
            blockers.append(
                {
                    "code": "sprint_not_locked",
                    "sprint_number": sprint.get("sprint_number"),
                    "status": status,
                    "message": "Every sprint must be queued or pending.",
                }
            )
        if status == "queued" and sprint.get("queue_position") is None:
            blockers.append(
                {
                    "code": "queued_sprint_missing_position",
                    "sprint_number": sprint.get("sprint_number"),
                    "message": "Queued sprint is missing queue_position.",
                }
            )
        if status == "pending" and not sprint.get("pending_reason"):
            blockers.append(
                {
                    "code": "pending_sprint_missing_reason",
                    "sprint_number": sprint.get("sprint_number"),
                    "message": "Pending sprint is missing pending_reason.",
                }
            )
    if not _pm_handoff_fidelity(parsed, sprints):
        blockers.append(
            {
                "code": "pm_handoff_fidelity",
                "message": "Body needs Goal, Key Decisions, Deliverable detail, and PM-level sprint items.",
            }
        )
    blockers.extend(scan_lockdown_phrases(markdown))

