def register_tool(
    name: str | None = None,
    *,
    schema: JSONDict | None = None,
    event_kind: EventKind = "tool_call",
    operation_kind: OperationKind = "write",
) -> Callable[[ToolCallable], ToolCallable]:
    return registry.tool(
        name,
        schema=schema,
        event_kind=event_kind,
        operation_kind=operation_kind,
    )


def _event_from_tool_call(
    *,
    entry: ToolEntry,
    arguments: JSONDict,
    result: JSONDict,
    tool_call: JSONDict,
    duration_ms: int,
) -> Event:
    text = None
    if entry.event_kind == "activity":
        text = _first_string(
            result.get("description"),
            result.get("text"),
            arguments.get("description"),
            arguments.get("text"),
        )
    return Event(
        ts=_now(),
        kind=entry.event_kind,
        name=entry.name,
        text=text,
        ms=duration_ms,
        tool_call_id=tool_call["id"],
    )


def _normalize_result(value: Any) -> JSONDict:
    if value is None:
        return {}
    if isinstance(value, dict):
        return value
    return {"value": value}


def _first_string(*values: Any) -> str | None:
    for value in values:
        if isinstance(value, str):
            return value
    return None


def _now() -> str:
    return datetime.now(UTC).isoformat(timespec="milliseconds").replace(
        "+00:00",
        "Z",
    )


